SELECT mnmt_no, cltr_nm, dpsl_mtd_cd, nmrd_adrs, pbct_begn_dtm, pbct_end_dtm, other_info
FROM public_data_raw


        AND dpsl_mtd_cd = #{dpslMtdCd}


        AND nmrd_adrs LIKE CONCAT('%', #{sido}, '%')


ORDER BY pbct_begn_dtm DESC
LIMIT #{numOfRows} OFFSET #{offset}

